CREATE TABLE `items` (
  `item_id` int(11) NOT NULL AUTO_INCREMENT,
  `product_id` int(11) DEFAULT NULL,
  `serial_number` varchar(50) DEFAULT NULL,
  `invoice_id` int(11) DEFAULT NULL,
  `status` tinyint(1) DEFAULT 1 COMMENT '1 available, 2 sold, 3 warranty, 4 out',
  `provider_warranty_date` date DEFAULT NULL,
  `sale_warranty_date` date DEFAULT NULL,
  `warranty_id` int(11) DEFAULT NULL,
  `notes` varchar(50) DEFAULT NULL,
  `store_id` int(11) DEFAULT NULL,
  `grade_id` int(11) DEFAULT NULL,
  `status_id` int(11) DEFAULT NULL,
  `cost` decimal(10,2) DEFAULT NULL COMMENT 'invoice cost',
  `price` decimal(10,2) DEFAULT NULL COMMENT 'sale price',
  `sale_id` int(11) DEFAULT NULL,
  `purchase_date` date DEFAULT NULL,
  `warranty_price` decimal(10,2) DEFAULT NULL,
  `sold_date` datetime DEFAULT NULL,
  `comission` decimal(10,2) DEFAULT NULL,
  `tax` decimal(10,2) DEFAULT NULL,
  `disccount` decimal(10,2) DEFAULT NULL,
  `out_inventory_id` int(11) DEFAULT NULL,
  `claim_id` int(11) DEFAULT NULL,
  `inventory_id` int(11) DEFAULT NULL,
  PRIMARY KEY (`item_id`) USING BTREE,
  KEY `fk_items_t_products_1` (`product_id`) USING BTREE,
  KEY `fk_items_t_po_1` (`invoice_id`) USING BTREE,
  KEY `fk_items_t_warranties_1_idx` (`warranty_id`) USING BTREE,
  CONSTRAINT `fk_items_t_po_1` FOREIGN KEY (`invoice_id`) REFERENCES `invoices` (`invoice_id`),
  CONSTRAINT `fk_items_t_products_1` FOREIGN KEY (`product_id`) REFERENCES `products` (`product_id`),
  CONSTRAINT `fk_items_t_warranties_1` FOREIGN KEY (`warranty_id`) REFERENCES `warranties` (`warranty_id`)
) ENGINE=InnoDB AUTO_INCREMENT=21458 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC;
