DROP TABLE IF EXISTS `products`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `products` (
  `product_id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(512) NOT NULL,
  `description` varchar(1024) DEFAULT NULL,
  `model` varchar(512) DEFAULT NULL,
  `sku` varchar(255) DEFAULT NULL,
  `brand_id` int(11) DEFAULT NULL,
  `year` int(11) DEFAULT NULL,
  `images` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL,
  `price` decimal(10,2) DEFAULT NULL,
  `min_price` decimal(10,2) DEFAULT NULL,
  `warranty_id` int(11) DEFAULT NULL,
  `screen_size` decimal(10,2) DEFAULT NULL,
  `category_id` int(11) DEFAULT NULL,
  `features` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL,
  `stock_type` int(11) NOT NULL DEFAULT 1 COMMENT '1 bulk, 2 unique serial',
  `tags` varchar(100) DEFAULT NULL,
  `cost` decimal(10,2) DEFAULT NULL,
  `prices` text DEFAULT NULL,
  PRIMARY KEY (`product_id`) USING BTREE,
  KEY `fk_products_brands_1` (`brand_id`) USING BTREE,
  KEY `fk_products_warranties_1_idx` (`warranty_id`) USING BTREE,
  CONSTRAINT `fk_products_brands_1` FOREIGN KEY (`brand_id`) REFERENCES `brands` (`brand_id`),
  CONSTRAINT `fk_products_warranties_1` FOREIGN KEY (`warranty_id`) REFERENCES `warranties` (`warranty_id`) ON DELETE NO ACTION ON UPDATE NO ACTION
) ENGINE=InnoDB AUTO_INCREMENT=374 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC;
