INSERT INTO `stores` VALUES (1,'Tv Super Store',2147483647,31.7825400000000000,-106.4259900000000000,1,'6317 N Eldridge pkwy, Ste #104','Houston','Tvsuperstore@icloud.com','3462377115',8.25,'Thank you for choosing Tv Super Store','All items sold are new, open box, repackaged, or factory renewd. ALL SALES ARE FINAL. No returns, refunds, or exchanges unless approved by management.\nCustomers must inspect merchandise before leaving the store. Tv Super Store is not responsible for damage, misuse, improper installation, electrical issues, or missing components after the item leaves the premises.\nTVs: 90-day limited store warranty for manufacturer defects only. Physical damage, cracked screens, liquid damage, power surges, misuse, or improper installation void warranty. Service must be handled at this location.\nAppliances: 30-day limited store warranty for manufacturer defects only. Physical or cosmetic damage, misuse, or improper installation void warranty. Service must be handled at this location.\nExtended Warranty (if purchased): After 30 days (appliances) or 90 days (TVs), claims must be filed directly with Consumer Priority Service (CPS). A $99 deductible per approved appliance claim may apply. Tv Super Store is not responsible for third-party warranty decisions or claims.\nMini Splits: No store warranty. Covered only under manufacturer warranty and valid only if installed by a licensed/certified HVAC professional. Proof of professional installation may be required.\nBy completing this purchase, customer agrees to these terms.',NULL,1,NULL,'Tvsuperstore@icloud.com');
