CREATE TABLE `transactions` (
  `transaction_id` int(11) NOT NULL AUTO_INCREMENT,
  `store_id` int(11) DEFAULT NULL,
  `product_id` int(11) DEFAULT NULL,
  `transaction_type` enum('Invoice','Sale','Refund','Inventory','Claim','Out of Inventory','Inventory adjustment','Cancelation','Transfer') DEFAULT NULL COMMENT '1 invoice, 2 sale, 3 warranty, 4 inventory, 6\r\nrefund, 7 claim, 8 transfer, 9  return,  10 ullage, 11 inventory exit',
  `status_id` int(11) DEFAULT NULL,
  `grade_id` int(11) DEFAULT NULL,
  `date` datetime DEFAULT NULL,
  `notes` varchar(255) DEFAULT NULL,
  `reference_id` int(11) DEFAULT NULL COMMENT 'warehouse, store, provider, customer,',
  `quantity` int(11) DEFAULT NULL,
  `quantity_inventory` int(11) DEFAULT NULL,
  `price` decimal(10,2) DEFAULT NULL COMMENT 'price/cost',
  `item_id` int(11) DEFAULT NULL,
  `warranty_id` int(11) DEFAULT NULL,
